1	import {
2	  type CSSProperties,
3	  type FocusEvent,
4	  type JSX,
5	  type KeyboardEvent,
6	  type MouseEvent,
7	  useCallback,
8	  useId,
9	  useRef,
10	} from 'react';
11	import { Icons, IconLabels, ICON_SIZE, type LucideLikeIcon } from '@bim-ai/ui';
12	
13	/**
14	 * TopBar — spec §11.
15	 *
16	 * Three regions:
17	 *   1. Left  (240 px): hamburger toggle, logo placeholder, project-name button.
18	 *   2. Center: mode pills traversable with arrow keys (`role="tablist"`).
19	 *   3. Right: command palette button, collaborators count, settings, theme
20	 *      toggle, avatar.
21	 *
22	 * The TopBar is purely presentational. State (current mode, theme,
23	 * collaborators) is owned by callers (Workspace + Mode-switching WP-D03).
24	 */
25	
26	export const WORKSPACE_MODES = [
27	  { id: 'plan', label: 'Plan', hotkey: '1' },
28	  { id: '3d', label: '3D', hotkey: '2' },
29	  { id: 'plan-3d', label: 'Plan + 3D', hotkey: '3' },
30	  { id: 'section', label: 'Section', hotkey: '4' },
31	  { id: 'sheet', label: 'Sheet', hotkey: '5' },
32	  { id: 'schedule', label: 'Schedule', hotkey: '6' },
33	  { id: 'agent', label: 'Agent', hotkey: '7' },
34	] as const;
35	
36	export type WorkspaceMode = (typeof WORKSPACE_MODES)[number]['id'];
37	
38	export interface TopBarProps {
39	  mode: WorkspaceMode;
40	  onModeChange: (next: WorkspaceMode) => void;
41	  projectName: string;
42	  onProjectNameClick?: () => void;
43	  /** Forwarded to the project-name pill so external popovers can anchor. */
44	  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
45	  onHamburgerClick?: () => void;
46	  theme: 'light' | 'dark';
47	  onThemeToggle?: () => void;
48	  onCommandPalette?: () => void;
49	  onSettings?: () => void;
50	  collaboratorsCount?: number;
51	  onCollaboratorsClick?: () => void;
52	  /** Identifier shown as the avatar fallback when no avatar URL is provided. */
53	  avatarInitials?: string;
54	}
55	
56	export function TopBar({
57	  mode,
58	  onModeChange,
59	  projectName,
60	  onProjectNameClick,
61	  projectNameRef,
62	  onHamburgerClick,
63	  theme,
64	  onThemeToggle,
65	  onCommandPalette,
66	  onSettings,
67	  collaboratorsCount,
68	  onCollaboratorsClick,
69	  avatarInitials,
70	}: TopBarProps): JSX.Element {
71	  const tablistId = useId();
72	  return (
73	    <div
74	      data-testid="topbar"
75	      role="banner"
76	      style={topBarStyle}
77	      className="flex w-full items-center gap-4 border-b border-border bg-background px-4"
78	    >
79	      <TopBarLeft
80	        projectName={projectName}
81	        onProjectNameClick={onProjectNameClick}
82	        projectNameRef={projectNameRef}
83	        onHamburgerClick={onHamburgerClick}
84	      />
85	      <TopBarModePills tablistId={tablistId} mode={mode} onModeChange={onModeChange} />
86	      <TopBarRight
87	        theme={theme}
88	        onThemeToggle={onThemeToggle}
89	        onCommandPalette={onCommandPalette}
90	        onSettings={onSettings}
91	        collaboratorsCount={collaboratorsCount}
92	        onCollaboratorsClick={onCollaboratorsClick}
93	        avatarInitials={avatarInitials}
94	      />
95	    </div>
96	  );
97	}
98	
99	const topBarStyle: CSSProperties = {
100	  height: 'var(--shell-topbar-height)',
101	  minHeight: 'var(--shell-topbar-height)',
102	};
103	
104	function TopBarLeft({
105	  projectName,
106	  onProjectNameClick,
107	  projectNameRef,
108	  onHamburgerClick,
109	}: {
110	  projectName: string;
111	  onProjectNameClick?: () => void;
112	  projectNameRef?: React.RefObject<HTMLButtonElement | null>;
113	  onHamburgerClick?: () => void;
114	}): JSX.Element {
115	  return (
116	    <div className="flex items-center gap-3" style={{ minWidth: 240 }}>
117	      <IconButton Icon={Icons.hamburger} label={IconLabels.hamburger} onClick={onHamburgerClick} />
118	      <div
119	        aria-label="BIM AI"
120	        className="flex h-6 w-6 items-center justify-center rounded bg-accent text-accent-foreground"
121	        style={{ fontWeight: 700, fontSize: 11, letterSpacing: '0.01em' }}
122	      >
123	        BA
124	      </div>
125	      <button
126	        type="button"
127	        ref={projectNameRef}
128	        onClick={onProjectNameClick}
129	        className="flex items-center gap-1.5 rounded-md px-2 py-1 text-sm font-semibold text-foreground hover:bg-surface"
130	        aria-haspopup="menu"
131	        data-testid="topbar-project-name"
132	      >
133	        <span className="truncate" style={{ maxWidth: 160 }}>
134	          {projectName}
135	        </span>
136	        <Icons.disclosureOpen size={14} className="text-muted" aria-hidden="true" />
137	      </button>
138	    </div>
139	  );
140	}
141	
142	function TopBarModePills({
143	  tablistId,
144	  mode,
145	  onModeChange,
146	}: {
147	  tablistId: string;
148	  mode: WorkspaceMode;
149	  onModeChange: (next: WorkspaceMode) => void;
150	}): JSX.Element {
151	  const tabRefs = useRef<Map<WorkspaceMode, HTMLButtonElement>>(new Map());
152	  const setTabRef = useCallback(
153	    (id: WorkspaceMode) => (el: HTMLButtonElement | null) => {
154	      if (el) tabRefs.current.set(id, el);
155	      else tabRefs.current.delete(id);
156	    },
157	    [],
158	  );
159	
160	  const handleKey = useCallback(
161	    (event: KeyboardEvent<HTMLDivElement>) => {
