  badge,
  'data-testid': testId,
  'data-current-theme': currentTheme,
}: IconButtonProps): JSX.Element {
  const handleFocus = useCallback((_e: FocusEvent<HTMLButtonElement>) => {
    /* no-op — declared so consumers can extend later. */
  }, []);

  return (
    <button
      type="button"
